import {
    _class,
    FORM_EVENTS,
    FormInputJson,
    LoginInputJson
} from "../env.js";
import DatePicker from "./date-picker.js";
import DOM from "./dom.js";
import DropdownSelect from "./dropdown.js";
import FormValidation from "./form-validation.js";

export default class FormManager {
    constructor( state ) {
        this.state = state;
        this.dom = new DOM();
        
        this.validation = new FormValidation({
            title: { required: true, minLength: 5, maxLength: 100 },
            description: { required: true, minLength: 10, maxLength: 500 },
        });;



        this.assignees = this.state.assignees;
        this.priority = this.state.priority;
        this.status = this.state.status;


        this.forms = new Map();

        this.formEvents = FORM_EVENTS;
        this.listeners = {};


        this.form = null;
        this.formType = null;
        this.taskId = null;

        
    }

    on(eventName, callback) {
        if (!this.listeners[eventName]) this.listeners[eventName] = [];
        this.listeners[eventName].push(callback);
    }

    off(eventName) {
        if (this.listeners[eventName]) {
            this.listeners[eventName] = [];
        }
    }

    trigger(eventName, data = null) {
        if (this.listeners[eventName]) {
            this.listeners[eventName].forEach((cb) => cb(data));
        }
    }

    _initListeners() {
        // const submitBtn = this.form.querySelector('#f--submit');
        // const cancelBtn = this.form.querySelector('#f--cancel');
        // const formType = this.form.getAttribute('data-form-type');

        const submitBtn = this.dom.getOne('#f--submit', this.form);
        const cancelBtn = this.dom.getOne('#f--cancel', this.form);
        const formType = this.dom.getAttr(this.form, 'data-form-type');
        

        if (submitBtn) {
            //submitBtn.removeEventListener('click', this._handleSubmit);
            this.dom.off(submitBtn, 'click', this._handleSubmit);
            
            if (formType === 'create') {
                this._handleSubmit = () => {
                    const formData = this._collectFormData(); // Get latest data
                    this.trigger(this.formEvents.formBeforeSubmit, formData);
                    this.trigger(this.formEvents.formSubmit, formData);
                };
            } else if (formType === 'update') {
                // Setup form watching for real-time updates
                this._setupFormWatch();
                this._handleSubmit = () => {
                    const formData = this._collectFormData(); // Get latest data
                    this.trigger(this.formEvents.formBeforeSubmit, formData);
                    this.trigger(this.formEvents.formUpdate, formData);
                };
            }
            
            this.dom.on(submitBtn, 'click', () => {
                const formData = this._collectFormData();
                const taskData = this.state.getTaskById(formData.id);
                if(taskData){
                    const isValid = this.validation.validate(this.form, formData, taskData);
                    if(!isValid) return;
                }
                this._handleSubmit();
            });
            
            // submitBtn.addEventListener('click', () => {
            //     const formData = this._collectFormData();
            //     const taskData = this.state.getTaskById(formData.id);
            //     if(taskData){
            //         const isValid = this.validation.validate(this.form, formData, taskData);
            //         if(!isValid) return;
            //     }
            //     this._handleSubmit();
            // });
        }

        if (cancelBtn) {
            //cancelBtn.removeEventListener('click', this._handleCancel);
            this.dom.off(cancelBtn, 'click', this._handleCancel);
            this._handleCancel = () => {
                this.removeForm();
                this.trigger(this.formEvents.formCancel);
            };
            // cancelBtn.addEventListener('click', this._handleCancel);
            this.dom.on(cancelBtn, 'click', this._handleCancel);
        }
    }

    _setupFormWatch() {
        // Get all form fields
        // const fields = this.form.querySelectorAll('[name]');
        const fields = this.dom.get('[name]', this.form);

        const taskData = this.state.getTaskById(this.taskId);
        const mousepos = {
            x: taskData.screeninfo.document.x,
            y: taskData.screeninfo.document.y
        }
        this.state.setState("mousePos", mousepos , 'form');
        // console.log({taskData});
        
        // Add event listeners to each field
        fields.forEach(field => {
            // const fieldName = field.getAttribute('name');
            // const type = field.getAttribute('type');

            const fieldName = this.dom.getAttr(field, 'name');
            const type = this.dom.getAttr(field, 'type');
            const event = type === "hidden" ? "change" : "input";

            this.dom.on(field, event, () => {
                const formData = this._collectFormData();
                const isValid = this.validation.validate(this.form, formData, taskData);
                
                // Trigger formWatch event with current data and validation status
                this.trigger(this.formEvents.formWatch, {
                    formData,
                    isValid,
                    changedField: fieldName,
                    element: field
                });
            });
        });
    }

    _collectFormData() {
        const data = {};
        if(this.formType === "update"){
            data.id = this.taskId;
        }

        const fields = this.form.querySelectorAll('[name]');
        
        fields.forEach((el) => {
            if (el.getAttribute('type') === 'hidden') {
                data[el.getAttribute('name')] = el.getAttribute('data-value');
                return;
            }
            data[el.getAttribute('name')] = el.innerText.trim();
        });
        return data;
    }





    #_create({
        id = '',
        className = ''
    }) {
        if (id === '' && className === '') {
            console.error("ID and className cannot be empty");
        }

        const element = document.createElement("div");
        if (id) {
            element.id = id;
        }
        if (className) {
            element.className = className;
        }

        return element;
    }

    loginForm(){
        const formHeader = this.#createFormHeader("Login");
        const formInputBody = this.#_create({
            className: `${_class.form.formInputGroup}`
        });
        const formInputJsonRes = LoginInputJson({
            isEditing: true,
            defaultValues: {
                email: "isha@2cube.studio",
                password: "isha@123",
            }
        });
        formInputBody.innerHTML = Object.keys(formInputJsonRes).map((key) => {
            return this.#createInput(formInputJsonRes[key]);
        }).join('');
        const formActionButton = this.#createFormActionButton({
            submit: true,
            cancel: true
        });
        const formWrapper = this.#_create({
            id: "loginFormWrapper"
        });
        const form = this.#_create({
            id: "loginForm",
            className: `${_class.form.wrapper}`
        });
        
        form.append(document.createRange().createContextualFragment(formHeader));
        form.append(formInputBody);
        form.append(document.createRange().createContextualFragment(formActionButton));
        form.setAttribute('data-form-type', 'login');
        form.classList.add('fi');
        formWrapper.appendChild(form);
        this.form = formWrapper;
        document.body.appendChild(formWrapper);
        const submitButton = this.dom.getOne('#f--submit', this.form)
        this.dom.on(submitButton, 'click', () => {
            const fields = this.form.querySelectorAll('[name]');
            const formData = {};
            fields.forEach((el) => {
                formData[el.getAttribute('name')] = el.innerText.trim();
            });
            this.trigger(this.formEvents.formLogin, formData);
        });
        
        const cancelButton = this.dom.getOne('#f--cancel', this.form)
        this.dom.on(cancelButton, 'click', () => {
            this.removeForm();
            this.trigger(this.formEvents.formCancel);
        });

        return this;
    }


    createForm({ viewportInfo, id, type, defaultValues = {}, reason = null}) {

        if (!id) {
            console.error("ID is required");
            return;
        }
        if (!type) {
            console.error("Type is required");
            return;
        }

        const not_allow_stages = [
            'form_created'
        ];
        if(not_allow_stages.includes(this.state.stage)){
            console.error(`Stage is ${this.state.stage}. it's not allowed`);
            return;
        }

        // here I need to check stage

        this.formType = type;
        let FormHeaderTitle = "New Bug Report";

        if(type === "update"){
            let defaultValues1 = this.state.getTaskById(defaultValues);
            this.taskId = defaultValues1.id;
            defaultValues = {
                id: defaultValues1.id,
                ft: defaultValues1.title,
                fd: defaultValues1.description,
                fdd: defaultValues1.due_date,
                fa: defaultValues1.assigned_to[0],
                fp: defaultValues1.priority,
                fs: defaultValues1.status,
            }
            FormHeaderTitle = "Update Bug Report";
        }

        const formHeader = this.#createFormHeader(FormHeaderTitle);
        const formInputBody = this.#_create({
            className: `${_class.form.formInputGroup}`
        });
        const formInputJsonRes = FormInputJson({
            isEditing: true,
            defaultValues: defaultValues
        });

        formInputBody.innerHTML = Object.keys(formInputJsonRes).map((key) => {
            return this.#createInput(formInputJsonRes[key]);
        }).join('');

        const formActionButton = this.#createFormActionButton({
            submit: true,
            cancel: true
        });
        const form = this.#_create({
            id: id,
            className: `${_class.form.wrapper}`
        });
        
        // Set the form type as a data attribute
        form.setAttribute('data-form-type', type);

        form.append(document.createRange().createContextualFragment(formHeader));
        form.append(formInputBody);
        form.append(document.createRange().createContextualFragment(formActionButton));
        this.form = form;
        this._dueDate('due_date',defaultValues.fdd);
        this._assignee('assigned_to',defaultValues.fa);
        this._priority('priority',defaultValues.fp);
        this._status('status',defaultValues.fs);
        document.body.appendChild(this.form);

        this._initListeners();
        
        // If it's an update form, set up form watching immediately
        // and validate the initial state to properly set the submit button state
        if (type === 'update') {
            //this._setupFormWatch();
            
            // Validate initial form state and disable submit button if needed
            const formData = this._collectFormData();
            const taskData = this.state.getTaskById(this.taskId);
            const isValid = this.validation.validate(this.form, formData, taskData);
            
            const submitBtn = this.form.querySelector('#f--submit');
            if (submitBtn && !isValid) {
                submitBtn.classList.add('disabled');
            }
        }

        // Trigger formCreate event AFTER the form is fully initialized
        this.trigger(this.formEvents.formCreate, {
            id: id,
            type: type,
            defaultValues,
            element: this.form
        });

        if(reason === 'marker_click'){
            this.state.setStage('form_view',`type:${type}>#createForm`);
        }else{
            this.state.setStage('form_created',`type:${type}>#createForm`);
        }
        
        return this;
    }

    removeForm( reason = null ) {
        
        if(reason === 'marker_click'){
            this.state.setStage('marker_click',`type:${this.formType}>#removeForm`);
        }else{
            this.state.setStage('init',`type:${this.formType}>#removeForm`);
        }
        this.form.remove();
        this.form = null;
    }

    #createFormHeader(title) {
        return `<div class="${_class.form.ft}"><div class="">${title}</div></div>`;
    }

    #createInput({
        placeholder,
        contenteditable = false,
        name = null,
        value = '',
        label = '',
        type = 'text',
        className = ''
    }) {
        if (name === null) {
            console.error("Name is required");
        }

        const _className = type === 'hidden' ? '' : `class="${_class.form.input}"`;
        contenteditable = type === 'hidden' ? false : contenteditable;

        return `<div class="${_class.form.inputWrapper} ${className}"><div class="${_class.form.label}">${label}</div><div ${_className} data-placeholder="${placeholder}"contenteditable="${contenteditable}"name="${name}"type="${type}"appearance="${type}">${value}</div></div>`;
    }

    #createFormActionButton({
        submit = true,
        cancel = true
    }) {
        // return `<div class="${_class.form.actionButton.wrapper}">// ${submit ? `<div id="f--submit" class="${_class.form.actionButton.submit}">Submit</div>` : null} // ${cancel ? `<div id="f--cancel" class="${_class.form.actionButton.cancel}">Cancel</div>` : null} // </div>`;
        return ` <div class="${_class.form.actionButton.wrapper}">${submit ? `<div id="f--submit" class="${_class.form.actionButton.submit}">Submit</div>` : ``} ${cancel ? `<div id="f--cancel" class="${_class.form.actionButton.cancel}">Cancel</div>` : ``} </div>`;
    }

    _dueDate( name , value = new Date() ){
        return new DatePicker({
            element:this.form.querySelector(`[name="${name}"]`),
            selectedDate: value,
            format: "DD-MMM-YYYY",
            showAdjacentMonthDays: true
        });
    }

    _assignee( name , value ){
        return new DropdownSelect({
            element:this.form.querySelector(`[name="${name}"]`),
            data: this.assignees,
            key:"user_name",
            value:"user_id",
            type: "single",
            placeholder: "Select assignee",
            preselected: [value],
        });
    }

    _priority( name , value ){
        return new DropdownSelect({
            element:this.form.querySelector(`[name="${name}"]`),
            data: this.priority,
            type: "single",
            placeholder: "Select priority",
            preselected: [value],
        });
    }

    _status( name , value ){
        return new DropdownSelect({
            element:this.form.querySelector(`[name="${name}"]`),
            data: this.status,
            type: "single",
            placeholder: "Select status",
            preselected: [value],
        });
    }



}
