export const getSystemInfo = () => {
    const ua = navigator.userAgent;
    const platform = navigator.userAgentData?.platform || navigator.platform;

    return {
        pixelRatio: window.devicePixelRatio,
        userAgent: ua,
        os: {
            name: getOSName(ua),
            version: getOSVersion(ua),
            type: platform
        },
        browserInfo: getBrowserInfo(ua)
    };
}

export const getDocumentInfo = () => {
    const orientation =
        (screen.orientation && screen.orientation.type) ||
        (window.innerWidth > window.innerHeight ? 'landscape-primary' : 'portrait-primary');
    return {
        height: document.documentElement.scrollHeight,
        width: document.documentElement.scrollWidth,
        x: 0,
        y: 0,
        scrollX: window.scrollX || window.pageXOffset,
        scrollY: window.scrollY || window.pageYOffset,
        orientation: orientation,
        vh: window.innerHeight,
        vw: window.innerWidth
    };
}

export const mousePosition = (e) => {
    // want to mouse position with sum of scroll document. so I get exact position of mouse
    return {
        x: e.clientX + window.scrollX,
        y: e.clientY + window.scrollY
    };
}


function getOSName(ua) {
    if (/Windows NT/i.test(ua)) return 'Windows';
    if (/Mac OS X/i.test(ua)) return 'macOS';
    if (/Linux/i.test(ua)) return 'Linux';
    if (/Android/i.test(ua)) return 'Android';
    if (/iPhone|iPad|iPod/i.test(ua)) return 'iOS';
    return 'Unknown';
}

function getOSVersion(ua) {
    const match = ua.match(/(Windows NT|Mac OS X|Android|CPU (iPhone)? OS)\s([\d_\.]+)/i);
    return match ? match[3].replace(/_/g, '.') : 'Unknown';
}

function getBrowserInfo(ua) {
    let name = 'Unknown',
        version = 'Unknown';

    if (/Edg\//i.test(ua)) {
        name = 'Edge';
        version = ua.match(/Edg\/([\d\.]+)/)[1];
    } else if (/Chrome\//i.test(ua)) {
        name = 'Chrome';
        version = ua.match(/Chrome\/([\d\.]+)/)[1];
    } else if (/Safari\//i.test(ua) && /Version\//i.test(ua)) {
        name = 'Safari';
        version = ua.match(/Version\/([\d\.]+)/)[1];
    } else if (/Firefox\//i.test(ua)) {
        name = 'Firefox';
        version = ua.match(/Firefox\/([\d\.]+)/)[1];
    }

    return {
        name,
        version,
        engine: navigator.product || 'Unknown'
    };
}